  ('social-worker-moex-01713', 'social-worker', 'social-worker-moex-108-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '一位身心障礙住宿機構主任，面臨政府組織經營績效評鑑在即，以及處理員工高離職率問題。評 鑑資料的事前準備非常辛苦，卻有助於印證領導者經營管理績效；員工離職率處理，可以減緩照 顧人力不足，且避免評鑑時開天窗，但留住劣質員工又造成影響優質同仁感受，打擊士氣，不曉 得該如何面對與抉擇，這是何種衝突？', '["雙趨衝突", "雙避衝突", "趨避衝突", "多重趨避衝突"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "c9da933020f6", "answer_pdf_sha1": "1c177e8bc0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
